import { useState } from 'react'
import { supabase } from '../lib/supabase'

const LOGO = 'https://fcsaintprex.ch/wp-content/uploads/2021/09/cropped-logo_fc_saint_prex.jpg'
const BG = 'data:image/jpeg;base64,'
const TEAM_PHOTO = 'data:image/jpeg;base64,'

export default function Login() {
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  const handleLogin = async (e) => {
    e.preventDefault()
    setLoading(true)
    setError('')
    const { error } = await supabase.auth.signInWithPassword({ email, password })
    if (error) {
      setError('Email ou mot de passe incorrect')
      setLoading(false)
    }
  }

  return (
    <div className="login-screen" style={{backgroundImage: `url(${BG})`, backgroundSize: 'cover', backgroundPosition: 'center'}}>
      <div className="login-overlay">
        <div className="login-box">
          <img src={LOGO} alt="FC Saint-Prex" onError={e => e.target.style.display='none'} />
          <h1>FC SAINT-PREX</h1>
          <p>Laissons dire et faisons bien</p>
          <form onSubmit={handleLogin}>
            <label className="form-label">Email</label>
            <input
              className="form-input"
              type="email"
              placeholder="votre@email.com"
              value={email}
              onChange={e => setEmail(e.target.value)}
              required
            />
            <label className="form-label">Mot de passe</label>
            <input
              className="form-input"
              type="password"
              placeholder="••••••••"
              value={password}
              onChange={e => setPassword(e.target.value)}
              required
            />
            {error && <div className="error-msg">{error}</div>}
            <button className="btn-primary" type="submit" disabled={loading} style={{marginTop: '8px'}}>
              {loading ? 'Connexion...' : 'Se connecter'}
            </button>
          </form>
        </div>
        <div className="team-photo-wrap">
          <img src={TEAM_PHOTO} alt="Équipe FC Saint-Prex" className="team-photo" />
          <div className="team-photo-caption">Seniors FC Amical Saint-Prex</div>
        </div>
      </div>
    </div>
  )
}
